{
  description = "Claude Code configuration and development environment";

  inputs = {
    nixpkgs.url = "github:nixos/nixpkgs/nixos-unstable";
  };

  outputs =
    { nixpkgs, ... }:
    let
      system = "x86_64-linux";
      pkgs = nixpkgs.legacyPackages.${system};

      agent-browser = pkgs.stdenv.mkDerivation rec {
        pname = "agent-browser";
        version = "0.22.3";

        src = pkgs.fetchurl {
          url = "https://registry.npmjs.org/${pname}/-/${pname}-${version}.tgz";
          hash = "sha256-0sg94n94y1i4r0s0ym8s9lk6cysbddq0wcfvxsz9fmm85bxx0cc7";
        };

        nativeBuildInputs = [ pkgs.autoPatchelfHook ];
        buildInputs = [ pkgs.stdenv.cc.cc.lib ];

        unpackPhase = ''
          mkdir -p $out
          tar xzf $src --strip-components=1 -C $out
        '';

        installPhase = ''
          mkdir -p $out/bin
          cp $out/package/bin/agent-browser-linux-x64 $out/bin/agent-browser
          chmod +x $out/bin/agent-browser
          rm -rf $out/package
        '';
      };
    in
    {
      devShells.${system}.default = pkgs.mkShell {
        packages = with pkgs; [
          claude-code
          mcp-nixos
          bun
          jq
          git
          agent-browser
        ];
      };
    };
}

